// Simple Knowledge Base
const documents = [
  "n8n is a workflow automation tool.",
  "Google Gemini is an AI model.",
  "This is a legacy workflow for older n8n versions."
];

// Get user input from Webhook query param 'text'
// Example: <your-n8n-url>/webhook/gemini-chat?text=What is n8n?
const userInput = items[0].json.query.text || "Hello";

// Simple Search
const relevantDocs = documents.filter(doc => doc.includes("n8n") || doc.includes("Gemini"));
const context = relevantDocs.join("\n");

return [
  {
    json: {
      context: context,
      query: userInput
    }
  }
];
